const body = $input.first().json.body || $input.first().json;
const message = body.message || '';
const workspace_id = body.workspace_id || null;
const session_id = body.session_id || crypto.randomUUID();
const user_id = body.user_id || null;
if (!message.trim()) throw new Error('message is required');
if (!user_id) throw new Error('user_id is required');

// Simple intent detection
const msg = message.toLowerCase();
let intent = 'general';
if (/validate|test.*idea|pressure test/.test(msg)) intent = 'validate_idea';
else if (/pitch|investor/.test(msg)) intent = 'pitch';
else if (/gtm|go.to.market|strategy/.test(msg)) intent = 'gtm';
else if (/offer|pricing|package/.test(msg)) intent = 'offer';
else if (/first.*customer|acquisition/.test(msg)) intent = 'first_customers';
else if (/follow.?up|email sequence/.test(msg)) intent = 'followup';
else if (/kill.*idea|devil/.test(msg)) intent = 'kill_idea';

return [{ json: { message, workspace_id, session_id, user_id, intent, now: new Date().toISOString() } }];

const ctx = $('Parse & Detect Intent').item.json;
const wsArr = $input.first().json;
const ws = Array.isArray(wsArr) ? wsArr[0] : wsArr;
return [{ json: { ...ctx, workspace: ws || null, lane: ws?.lane || 'Idea', stage: ws?.stage || 'Idea' } }];

const resp = $input.first().json;
const ctx = $('Merge Context').item.json;
return [{ json: { ...resp, intent: ctx.intent, lane: ctx.lane, workspace_id: ctx.workspace?.id || null } }];
